import{_ as t,o as d,c as o,ae as c}from"./chunks/framework.Dn7Y7LSn.js";const p=JSON.parse('{"title":"API Overview","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"dev/api.md","filePath":"dev/api.md"}'),a={name:"dev/api.md"};function l(i,e,r,s,n,u){return d(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="api-overview" tabindex="-1">API Overview <a class="header-anchor" href="#api-overview" aria-label="Permalink to &quot;API Overview&quot;">​</a></h1><p>Ilias can be understood in six layers: runtime, tasks, I/O, networking, synchronization, and optional extensions. In day-to-day development, you usually only need a small subset of headers.</p><h2 id="recommended-entry-headers" tabindex="-1">Recommended entry headers <a class="header-anchor" href="#recommended-entry-headers" aria-label="Permalink to &quot;Recommended entry headers&quot;">​</a></h2><ul><li><code>#include &lt;ilias.hpp&gt;</code></li><li><code>#include &lt;ilias/platform.hpp&gt;</code></li><li><code>#include &lt;ilias/task.hpp&gt;</code></li><li><code>#include &lt;ilias/io.hpp&gt;</code></li><li><code>#include &lt;ilias/net.hpp&gt;</code></li><li><code>#include &lt;ilias/fs.hpp&gt;</code></li><li><code>#include &lt;ilias/sync.hpp&gt;</code></li><li><code>#include &lt;ilias/tls.hpp&gt;</code></li><li><code>#include &lt;ilias/process.hpp&gt;</code></li><li><code>#include &lt;ilias/signal.hpp&gt;</code></li></ul><h2 id="module-summary" tabindex="-1">Module summary <a class="header-anchor" href="#module-summary" aria-label="Permalink to &quot;Module summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Main APIs</th><th>Purpose</th></tr></thead><tbody><tr><td>platform</td><td><code>PlatformContext</code>, <code>ilias_main</code></td><td>Install the current-thread executor and start async programs</td></tr><tr><td>task</td><td><code>Task&lt;T&gt;</code>, <code>spawn</code>, <code>whenAll</code>, <code>whenAny</code>, <code>TaskScope</code>, <code>TaskGroup&lt;T&gt;</code>, <code>Thread</code></td><td>Write and organize coroutines</td></tr><tr><td>runtime</td><td><code>Executor</code>, stop token, <code>this_coro::*</code></td><td>Execution, cancellation, coroutine context access</td></tr><tr><td>io</td><td><code>BufReader</code>, <code>BufWriter</code>, <code>BufStream</code>, <code>readAll</code>, <code>writeAll</code>, <code>getline</code></td><td>Uniform stream-oriented I/O</td></tr><tr><td>net</td><td><code>TcpStream</code>, <code>TcpListener</code>, <code>UdpSocket</code>, <code>AddressInfo</code></td><td>Networking</td></tr><tr><td>fs</td><td><code>File</code>, <code>OpenOptions</code></td><td>File I/O</td></tr><tr><td>sync</td><td><code>Mutex</code>, <code>Event</code>, <code>Semaphore</code>, <code>oneshot::channel&lt;T&gt;</code>, <code>mpsc::channel&lt;T&gt;()</code></td><td>Synchronization and messaging</td></tr><tr><td>tls</td><td><code>TlsContext</code>, <code>TlsStream&lt;T&gt;</code></td><td>TLS client/server support</td></tr><tr><td>process</td><td><code>Process::Builder</code>, <code>Process</code></td><td>Async child processes</td></tr><tr><td>signal</td><td><code>signal::ctrlC()</code></td><td>Graceful console shutdown</td></tr></tbody></table><h2 id="key-public-concepts" tabindex="-1">Key public concepts <a class="header-anchor" href="#key-public-concepts" aria-label="Permalink to &quot;Key public concepts&quot;">​</a></h2><h3 id="task-t-and-iotask-t" tabindex="-1"><code>Task&lt;T&gt;</code> and <code>IoTask&lt;T&gt;</code> <a class="header-anchor" href="#task-t-and-iotask-t" aria-label="Permalink to &quot;`Task&lt;T&gt;` and `IoTask&lt;T&gt;`&quot;">​</a></h3><ul><li><code>Task&lt;T&gt;</code>: regular async result</li><li><code>IoTask&lt;T&gt;</code>: I/O result, effectively <code>Task&lt;Result&lt;T, std::error_code&gt;&gt;</code></li></ul><h3 id="unified-stream-model" tabindex="-1">Unified stream model <a class="header-anchor" href="#unified-stream-model" aria-label="Permalink to &quot;Unified stream model&quot;">​</a></h3><p>Many types expose similar operations:</p><ul><li><code>read(MutableBuffer)</code></li><li><code>write(Buffer)</code></li><li><code>flush()</code></li><li><code>shutdown()</code></li><li><code>close()</code> / <code>cancel()</code></li></ul><p>That makes protocol code reusable across <code>TcpStream</code>, <code>TlsStream&lt;T&gt;</code>, <code>File</code>, and <code>BufStream&lt;T&gt;</code>.</p><h3 id="structured-concurrency" tabindex="-1">Structured concurrency <a class="header-anchor" href="#structured-concurrency" aria-label="Permalink to &quot;Structured concurrency&quot;">​</a></h3><ul><li><code>TaskScope</code>: parent-child lifetime management</li><li><code>TaskGroup&lt;T&gt;</code>: batch task result collection</li></ul><h3 id="cancellation-model" tabindex="-1">Cancellation model <a class="header-anchor" href="#cancellation-model" aria-label="Permalink to &quot;Cancellation model&quot;">​</a></h3><p>Ilias uses stop tokens rather than making cancellation exception-only.</p><p>Common APIs:</p><ul><li><code>this_coro::stopToken()</code></li><li><code>this_coro::isStopRequested()</code></li><li><code>this_coro::stopped()</code></li><li><code>handle.stop()</code></li></ul><h2 id="suggested-reading-order" tabindex="-1">Suggested reading order <a class="header-anchor" href="#suggested-reading-order" aria-label="Permalink to &quot;Suggested reading order&quot;">​</a></h2><ol><li><a href="/guides/quick-start.html">Quick Start</a></li><li><a href="/guides/what-is-ilias.html">What is ilias</a></li><li>The public headers under <code>include/ilias/</code></li></ol>',21)])])}const m=t(a,[["render",l]]);export{p as __pageData,m as default};
